//#region src/lib/content.ts
var API_BASE = "http://backend:8001/api";
function getCsrfToken() {
	const match = document.cookie.match(/csrftoken=([^;]+)/);
	return match ? match[1] : "";
}
async function apiFetch(path, options = {}) {
	const isFormData = options.body instanceof FormData;
	const headers = {};
	if (!isFormData) headers["Content-Type"] = "application/json";
	if ((options.method || "GET").toUpperCase() !== "GET") headers["X-CSRFToken"] = getCsrfToken();
	return fetch(`${API_BASE}${path}`, {
		...options,
		headers: {
			...headers,
			...options.headers || {}
		},
		credentials: "include"
	});
}
async function readContent() {
	const res = await apiFetch("/content");
	if (!res.ok) throw new Error(`Failed to fetch content: ${res.status}`);
	return res.json();
}
async function contentAction(d) {
	if (d.action === "read") return readContent();
	if (d.action === "write" && d.section && d.content !== void 0) {
		const res = await apiFetch(`/content/${d.section}`, {
			method: "PATCH",
			body: JSON.stringify({ data: d.content })
		});
		if (!res.ok) {
			const err = await res.json().catch(() => ({}));
			throw new Error(err.error || `Failed to save: ${res.status}`);
		}
		return { success: true };
	}
	return {
		success: false,
		error: "Invalid action"
	};
}
async function verifyPassword(d) {
	return (await (await apiFetch("/auth/login", {
		method: "POST",
		body: JSON.stringify({
			username: "admin",
			password: d.data.password
		})
	})).json()).success === true;
}
async function updatePassword(d) {
	return (await apiFetch("/auth/change-password", {
		method: "POST",
		body: JSON.stringify({
			current_password: d.data.currentPassword,
			new_password: d.data.newPassword
		})
	})).json();
}
//#endregion
export { verifyPassword as i, readContent as n, updatePassword as r, contentAction as t };
